1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	const BASE_PREMIUM: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	
17	type Item = { type: string };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Input = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
20	type QuoteResult = { premium: number };
21	
22	const countByType = (items: Item[]): Map<string, number> => {
23	  const counts = new Map<string, number>();
24	  for (const item of items) {
25	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
26	  }
27	  return counts;
28	};
29	
30	const basePremiumForType = (type: string, count: number): number => {
31	  const unit = BASE_PREMIUM[type];
32	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
33	    return BLOCK_BASE_PREMIUM;
34	  }
35	  return unit * count;
36	};
37	
38	const basePremium = (items: Item[]): number => {
39	  let total = 0;
40	  for (const [type, count] of countByType(items)) {
41	    total += basePremiumForType(type, count);
42	  }
43	  return total;
44	};
45	
46	// MHPCO always rounds premiums in its own favor (up).
47	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
48	
49	const quotePremium = (step: QuoteStep): QuoteResult => {
50	  const base = basePremium(step.items);
51	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
52	  return {
53	    premium: roundUpInMHPCOFavor(base + firstInsuranceSurcharge + PROCESSING_FEE),
54	  };
55	};
56	
57	export const run = (input: Input): { results: QuoteResult[] } => ({
58	  results: input.steps.map(quotePremium),
59	});
